/* Design Tokens — The Obsidian Assembly Clone */

:root {
  /* ===== COLORS ===== */
  --c-black: #151415;
  --c-black-rgb: 21, 20, 21;
  --c-white: #fff;
  --c-white-rgb: 255, 255, 255;
  --c-grey: #3f383c;
  --c-grey-rgb: 63, 56, 60;
  --c-stone: #242324;
  --c-stone-rgb: 36, 35, 36;
  --c-yellow: #c9a96e;
  --c-yellow-rgb: 201, 169, 110;
  --c-brown: #6b4226;
  --c-brown-rgb: 107, 66, 38;
  --c-purple: #7a6b7a;
  --c-grey-dark: #2a2428;
  --c-berry: #8b3a62;

  /* ===== TYPOGRAPHY SCALE ===== */
  --type-step: 1.25;
  --body-font-size: 1rem;
  --body-line-height: 1.3;

  /* Spacing derived from type scale */
  --p: 1rem;
  --m: calc(var(--p) / var(--type-step));
  --mm: calc(var(--m) / var(--type-step));

  /* Font sizes (heading/display) */
  --h6: calc(var(--p) * var(--type-step));
  --h5: calc(var(--h6) * var(--type-step));
  --h4: calc(var(--h5) * var(--type-step));
  --h3: calc(var(--h4) * var(--type-step));
  --h2: calc(var(--h3) * var(--type-step));
  --h1: calc(var(--h2) * var(--type-step));
  --h0: calc(var(--h1) * var(--type-step));
  --large: max(calc(var(--h0) * var(--type-step) * var(--type-step)), 12.5vw);

  /* Line heights */
  --line-height-step: var(--body-line-height) / var(--type-step);
  --h0-lh: calc(var(--body-line-height) * pow(var(--line-height-step), -4));
  --h1-lh: calc(var(--body-line-height) * pow(var(--line-height-step), -4));
  --h2-lh: calc(var(--body-line-height) * pow(var(--line-height-step), -4));
  --h3-lh: calc(var(--body-line-height) * pow(var(--line-height-step), -4));
  --h4-lh: calc(var(--body-line-height) * pow(var(--line-height-step), -3));
  --h5-lh: calc(var(--body-line-height) * pow(var(--line-height-step), -2));
  --h6-lh: calc(var(--body-line-height) * pow(var(--line-height-step), -1));
  --large-lh: calc(var(--body-line-height) * pow(var(--line-height-step), -13));

  /* ===== FONTS ===== */
  --font-t-1: "Cormorant Garamond", serif;
  --font-t-2: "DM Serif Display", serif;
  --font-b-medium: "Inter", system-ui, -apple-system, sans-serif;
  --font-b-regular: "Inter", system-ui, -apple-system, sans-serif;
  --font: var(--font-b-regular);

  /* ===== GRID SYSTEM ===== */
  --g-columns: 12;
  --g-gap: 1rem;
  --g-margin: 1rem;

  /* ===== VIEWPORT UNITS ===== */
  /* Set by js/scroll.js on mount and resize */
  --vh: 1vh;
  --vw: 1vw;

  /* ===== EASING / TIMING ===== */
  --f-cubic: cubic-bezier(0.25, 0.1, 0.25, 1);
  --f-fast: cubic-bezier(0.22, 0.31, 0, 1);
  --f-cubic-in: cubic-bezier(0.55, 0, 1, 0.45);
  --f-smooth: cubic-bezier(0.45, 0.05, 0.55, 0.95);
}

/* Responsive scaling */
@media (max-width: 1024px) {
  :root {
    --large: var(--h0);
    --g-gap: 0.75rem;
    --g-margin: 0.75rem;
  }
}

@media (max-width: 640px) {
  :root {
    --body-font-size: 0.875rem;
    --g-gap: 0.5rem;
    --g-margin: 0.5rem;
  }
}

/* CSS @property for animation targets */
@property --progress {
  syntax: "<number>";
  inherits: true;
  initial-value: 0;
}

@property --slide-progress {
  syntax: "<angle>";
  inherits: true;
  initial-value: 0deg;
}

@property --connection-progress {
  syntax: "<number>";
  inherits: true;
  initial-value: 0;
}

@property --local-progress {
  syntax: "<number>";
  inherits: true;
  initial-value: 0;
}

@property --spotlight-angle {
  syntax: "<angle>";
  inherits: true;
  initial-value: 0deg;
}

@property --spotlight-distance {
  syntax: "<number>";
  inherits: true;
  initial-value: 0;
}

