/**
 * Places Carousel
 * 7-slide carousel with rotation progress indicator
 * Auto-advances every 6000ms, pause on hover
 */

const placesCarousel = document.getElementById('places-carousel');
if (!placesCarousel) {
  console.warn('Places carousel element not found');
} else {
  const items = placesCarousel.querySelectorAll('.carousel-item');
  const prevBtn = placesCarousel.querySelector('.carousel-prev');
  const nextBtn = placesCarousel.querySelector('.carousel-next');
  let currentIndex = 0;
  let autoplayInterval = null;
  let rafId = null;
  let slideProgress = 0;
  let targetProgress = 0;
  let isTransitioning = false;

  function setCurrentItem(index) {
    items.forEach((item, i) => {
      item.classList.toggle('active', i === index);
    });
    currentIndex = index;
  }

  function updateProgress() {
    if (Math.abs(slideProgress - targetProgress) > 0.001) {
      slideProgress += (targetProgress - slideProgress) * 0.1;
      const degrees = slideProgress * 360;
      placesCarousel.style.setProperty('--slide-progress', `${degrees}deg`);
      rafId = requestAnimationFrame(updateProgress);
    }
  }

  function nextSlide() {
    currentIndex = (currentIndex + 1) % items.length;
    setCurrentItem(currentIndex);
    targetProgress = (currentIndex / items.length);
    updateProgress();

    clearInterval(autoplayInterval);
    startAutoplay();
  }

  function prevSlide() {
    currentIndex = (currentIndex - 1 + items.length) % items.length;
    setCurrentItem(currentIndex);
    targetProgress = (currentIndex / items.length);
    updateProgress();

    clearInterval(autoplayInterval);
    startAutoplay();
  }

  function startAutoplay() {
    autoplayInterval = setInterval(() => {
      nextSlide();
    }, 6000);
  }

  // Event listeners
  if (prevBtn) prevBtn.addEventListener('click', prevSlide);
  if (nextBtn) nextBtn.addEventListener('click', nextSlide);

  // Hover pause/resume
  placesCarousel.addEventListener('mouseenter', () => {
    clearInterval(autoplayInterval);
  });
  placesCarousel.addEventListener('mouseleave', () => {
    startAutoplay();
  });

  // Initialize
  setCurrentItem(0);
  startAutoplay();
}

