/**
 * Objects Section
 * 4-card sequence carousel with scroll-based progress
 */

const objectsRoot = document.getElementById('objects-root');
if (!objectsRoot) {
  console.warn('Objects section not found');
} else {
  const objects = objectsRoot.querySelectorAll('.object');

  // Use GSAP ScrollTrigger for scroll-driven animation
  gsap.registerPlugin(ScrollTrigger);

  ScrollTrigger.create({
    trigger: objectsRoot,
    start: 'top center',
    end: 'bottom center',
    onUpdate: (self) => {
      const progress = self.progress;
      const numObjects = objects.length;
      const activeIndex = Math.floor(progress * numObjects) % numObjects;

      objects.forEach((obj, i) => {
        obj.classList.toggle('active', i === activeIndex);
      });

      objectsRoot.style.setProperty('--local-progress', progress);
    },
  });
}

