1	/**
2	 * Menu & Form Overlay System
3	 * Handles open/close of full-screen menu and form overlays
4	 * Manages .-isolate class on <html> for scroll locking
5	 */
6	
7	const html = document.documentElement;
8	const header = document.querySelector('header');
9	const menuOverlay = document.getElementById('menu-overlay');
10	const formOverlay = document.getElementById('form-overlay');
11	const successModal = document.getElementById('success-modal');
12	
13	let menuOpen = false;
14	let formOpen = false;
15	let scrollPosition = 0;
16	
17	/**
18	 * Toggle menu visibility
19	 */
20	function toggleMenu() {
21	  menuOpen = !menuOpen;
22	
23	  if (menuOpen) {
24	    scrollPosition = window.scrollY;
25	    menuOverlay.style.display = 'block';
26	    menuOverlay.style.setProperty('--top-position', scrollPosition);
27	    header.classList.add('-hidden');
28	    html.classList.add('-isolate');
29	  } else {
30	    menuOverlay.style.display = 'none';
31	    header.classList.remove('-hidden');
32	    html.classList.remove('-isolate');
33	  }
34	}
35	
36	/**
37	 * Toggle form visibility
38	 */
39	function toggleForm() {
40	  formOpen = !formOpen;
41	
42	  if (formOpen) {
43	    scrollPosition = window.scrollY;
44	    formOverlay.style.display = 'block';
45	    formOverlay.style.setProperty('--top-position', scrollPosition);
46	    header.classList.add('-hidden');
47	    html.classList.add('-isolate');
48	  } else {
49	    formOverlay.style.display = 'none';
50	    header.classList.remove('-hidden');
51	    html.classList.remove('-isolate');
52	  }
53	}
54	
55	/**
56	 * Close success modal
57	 */
58	function closeSuccessModal() {
59	  successModal.style.display = 'none';
60	  html.classList.remove('-isolate');
61	}
62	
63	/**
64	 * Show success modal (called after form submit)
65	 */
66	function showSuccessModal() {
67	  successModal.style.display = 'block';
68	  html.classList.add('-isolate');
69	}
70	
71	/**
72	 * Attach event listeners
73	 */
74	function initMenuSystem() {
75	  // Toggle menu buttons
76	  document.querySelectorAll('[data-action="toggle-menu"]').forEach(btn => {
77	    btn.addEventListener('click', toggleMenu);
78	  });
79	
80	  // Toggle form buttons
81	  document.querySelectorAll('[data-action="toggle-form"]').forEach(btn => {
82	    btn.addEventListener('click', toggleForm);
83	  });
84	
85	  // Close modal buttons
86	  document.querySelectorAll('[data-action="close-modal"]').forEach(btn => {
87	    btn.addEventListener('click', closeSuccessModal);
88	  });
89	
