/**
 * Updates Section
 * 5-item hover carousel with state machine
 */

const updatesCarousel = document.getElementById('updates-carousel');
if (!updatesCarousel) {
  console.warn('Updates carousel element not found');
} else {
  const items = updatesCarousel.querySelectorAll('.update-item');
  let currentIndex = 0;
  let hoverIndex = null;
  let autoplayInterval = null;

  function setCurrentItem(index) {
    hoverIndex = null;
    items.forEach((item, i) => {
      item.classList.toggle('active', i === index);
    });
    currentIndex = index;
  }

  function nextSlide() {
    currentIndex = (currentIndex + 1) % items.length;
    setCurrentItem(currentIndex);
  }

  function startAutoplay() {
    autoplayInterval = setInterval(() => {
      nextSlide();
    }, 6000);
  }

  // Hover handlers
  items.forEach((item, index) => {
    item.addEventListener('mouseenter', () => {
      hoverIndex = index;
      items.forEach((i) => {
        i.classList.toggle('active', index === items.indexOf(i));
      });
      clearInterval(autoplayInterval);
    });

    item.addEventListener('mouseleave', () => {
      setCurrentItem(currentIndex);
      startAutoplay();
    });
  });

  // Initialize
  setCurrentItem(0);
  startAutoplay();
}

