  content: "";
  display: block;
  flex-basis: 0;
  flex-grow: 0;
  flex-shrink: 1;
  padding-right: 0;
  transition: flex-grow 0.9s var(--f-cubic), padding-right 0.9s var(--f-cubic);
}

header .-w .menu-wrap .button {
  align-items: center;
  display: flex;
  flex-basis: 0;
  flex-grow: 2;
  flex-shrink: 1;
  justify-content: center;
