    to right,
    var(--c-yellow) 25%,
    var(--c-black) 25%,
    var(--c-black) 50%,
    var(--c-yellow) 50%,
    var(--c-yellow) 75%,
    var(--c-black) 75%
  );
  content: "";
  display: block;
  height: 1px;
  transition: background-position 0.9s var(--f-cubic);
  width: 100%;
}

header .-w .menu-wrap .button .menu-icon:before {
  background-position: 25%;
  background-size: 400% 1px;
}

header .-w .menu-wrap .button .menu-icon:after {
  background-position: 25%;
  background-size: 200% 1px;
}

