@media (min-width: 1024px) {
  header .-w .menu-wrap .button:hover .menu-icon {
    background-position: 0;
  }

  header .-w .menu-wrap .button:hover .menu-icon:before {
    background-position: 75%;
  }

  header .-w .menu-wrap .button:hover .menu-icon:after {
    background-position: 100%;
  }

