    color: var(--c-white);
  }
}

/* Scrolled state */
header.-scrolled .-w .request {
  opacity: 1;
  pointer-events: all;
  transition: translate 0.9s var(--f-cubic-in), opacity 0.9s var(--f-cubic-in), background-color 0.9s var(--f-cubic);
  translate: 0 0;
}

header.-scrolled .-w .menu-wrap:before {
  flex-grow: 1;
  padding-right: calc(var(--g-gap) * 2);
}

header.-scrolled .-w .menu-wrap .button {
  flex-grow: 1;
}

header.-scrolled .-w .menu-wrap .button .menu-icon {
  left: 50%;
  translate: -50%;
}

header.-scrolled .-w .menu-wrap .button .text {
  opacity: 0;
  translate: 0 -100%;
}

/* Dark mode */
header.-dark .-w a {
  color: var(--c-black);
}

header.-dark .-w a .-mm {
  color: rgba(var(--c-black-rgb), 0.4);
}

header.-dark .-w a:hover {
  color: var(--c-brown);
}

header.-dark .-w > .button .text {
  color: var(--c-black);
}

/* Hidden state (menu/form open) */
header.-hidden .-w {
  transform: translate3d(0, -150%, 0) skew(0deg, 0deg);
  transition: transform 1.5s var(--f-fast);
}

/* Initial load state */
html:not(.-ready) header .-w {
  transform: translate3d(0, -150%, 0) skew(-10deg, -5deg);
}

html.-loaded header .-w {
  transition: transform 2.1s var(--f-cubic-in);
}

/* Desktop adjustments */
@media (min-width: 1024px) {
  header .-w .sep {
    --left: 6;
  }

  header .-w > .button {
    --width: 2;
  }

  header .-w .places {
    --left: 5;
  }

  header .-w .objects {
    --left: 7;
  }

  header .-w .request {
    --left: 10;
  }

  header .-w .menu-wrap {
    --left: 11;
  }

  header .-w .menu-wrap .button {
    max-height: none;
  }
}

/* Mobile */
@media (max-width: 1023px) {
  header {
    padding-bottom: var(--h2);
  }

  header .-w .places,
  header .-w .objects,
  header .-w .request {
    display: none;
  }

  header .-w .menu-wrap {
    --left: 3;
  }
}

