  constructor(canvas, options = {}) {
    this.canvas = canvas;
    this.options = {
      imageSrc: options.imageSrc || 'images/stone-wall.webp',
      radius: options.radius || 280,
      reliefIntensity: options.reliefIntensity || 18,
      parallax: options.parallax || 8,
      ...options,
    };

    // For now, just draw a simple fallback
    this.initFallback();
  }

  initFallback() {
    // Placeholder: draw a simple gradient
    const ctx = this.canvas.getContext('2d');
    if (!ctx) return;

    ctx.fillStyle = 'rgba(21, 20, 21, 1)';
    ctx.fillRect(0, 0, this.canvas.width, this.canvas.height);

    // Draw a subtle gradient
    const gradient = ctx.createLinearGradient(0, 0, this.canvas.width, this.canvas.height);
    gradient.addColorStop(0, 'rgba(60, 56, 60, 0.3)');
    gradient.addColorStop(0.5, 'rgba(36, 35, 36, 0.5)');
    gradient.addColorStop(1, 'rgba(21, 20, 21, 0.7)');
    ctx.fillStyle = gradient;
    ctx.fillRect(0, 0, this.canvas.width, this.canvas.height);
