/**
 * Admission Section
 * Form handling and image sequence carousel
 */

const admissionForm = document.getElementById('admission-form');
if (admissionForm) {
  // Basic form validation
  admissionForm.addEventListener('submit', (e) => {
    e.preventDefault();

    // Validate required fields
    const name = admissionForm.querySelector('input[name="name"]').value.trim();
    const email = admissionForm.querySelector('input[name="email"]').value.trim();
    const country = admissionForm.querySelector('input[name="country"]').value.trim();
    const city = admissionForm.querySelector('input[name="city"]').value.trim();
    const context = admissionForm.querySelector('textarea[name="context"]').value.trim();
    const agreement = admissionForm.querySelector('input[name="agreement"]').checked;

    if (!name || name.length < 2) {
      alert('Please enter your full name');
      return;
    }

    if (!email || !email.includes('@')) {
      alert('Please enter a valid email address');
      return;
    }

    if (!country) {
      alert('Please enter your country');
      return;
    }

    if (!city) {
      alert('Please enter your city');
      return;
    }

    if (!context || context.length < 10) {
      alert('Please provide at least 10 characters of context');
      return;
    }

    if (!agreement) {
      alert('Please agree to the terms');
      return;
    }

    // Show success modal (handled by menu.js)
    const successModal = document.getElementById('success-modal');
    if (successModal) {
      successModal.style.display = 'block';
      document.documentElement.classList.add('-isolate');
    }

    // Reset form
    admissionForm.reset();
  });
}

