/* ===== STATE CLASSES ===== */

html.not\:-ready {
  /* Before initial load, hide most content */
}

html.html\:-loaded header {
  animation: headerEnter 2.1s var(--f-cubic-in);
}

@keyframes headerEnter {
  from {
    transform: translate3d(0, -150%, 0) skew(-10deg, -5deg);
  }
  to {
    transform: translate3d(0, 0, 0) skew(0, 0);
  }
}

html.html\:-isolate {
  overflow: hidden;
}

