/* ===== PAGE TRANSITION OVERLAY ===== */

#page-transition {
  position: fixed;
  inset: 0;
  z-index: 9999;
  pointer-events: none;
}

#page-transition .g {
  display: grid;
  grid-template-columns: repeat(4, 1fr);
  height: 100%;
}

#page-transition .g span {
  background-color: var(--c-black);
  transform: scaleY(0);
  transform-origin: bottom center;
}

#page-transition.-active .g span {
  transform: scaleY(1);
  transition: transform 0.6s var(--f-fast);
  transition-delay: calc((var(--order) - 1) * 0.07s);
}

#page-transition .t {
  position: absolute;
  inset: 0;
  display: flex;
  align-items: center;
  justify-content: center;
  opacity: 0;
  transition: opacity 0.3s var(--f-cubic);
}

#page-transition.-active .t {
  opacity: 1;
  transition-delay: 0.5s;
}

#page-transition .t span {
  color: var(--c-yellow);
  display: flex;
  flex-direction: column;
  align-items: flex-start;
}

#mobile-transition {
  position: fixed;
  inset: 0;
  z-index: 9998;
  background-color: var(--c-black);
  transform: scaleY(0);
  transform-origin: bottom center;
  pointer-events: none;
}

#mobile-transition.-active {
  transform: scaleY(1);
  transition: transform 0.5s var(--f-fast);
}

/* Overlay / full-screen menu & form base */
.full-screen-menu,
.full-screen-form {
  position: fixed;
  inset: 0;
  z-index: 200;
  overflow: hidden;
}

.full-screen-menu .overlay,
.full-screen-form .overlay {
  position: absolute;
  inset: 0;
  background-color: rgba(var(--c-black-rgb), 0.6);
  backdrop-filter: blur(4px);
}

.full-screen-menu .oy,
.full-screen-form .oy {
  position: absolute;
  inset: 0;
  overflow-y: auto;
  padding: var(--h1) 0 var(--h2);
}

.full-screen-menu .-w,
.full-screen-form .-w {
  position: relative;
  z-index: 1;
}

.button-close {
  --left: 11;
  --width: 2;
  color: var(--c-yellow);
  font-family: var(--font-b-medium);
  font-size: var(--mm);
  text-transform: uppercase;
  letter-spacing: 0.1em;
  cursor: pointer;
  align-self: start;
}

/* Menu nav */
.full-screen-menu nav {
  --left: 1;
  --width: 12;
  display: flex;
  flex-direction: column;
  gap: var(--g-gap);
  padding-top: var(--h1);
}

.full-screen-menu nav .guy {
  display: flex;
  align-items: center;
  gap: var(--p);
  margin-bottom: var(--h3);
}

.full-screen-menu nav .guy img {
  width: 60px;
  height: 60px;
  border-radius: 50%;
  object-fit: cover;
  flex-shrink: 0;
}

.full-screen-menu nav a,
.full-screen-menu nav span {
  color: var(--c-yellow);
  display: block;
  font-family: var(--font-t-1);
}

/* Form overlay layout */
.full-screen-form form {
  --left: 3;
  --width: 8;
  display: grid;
  gap: var(--h3);
  padding-top: var(--h1);
}

.full-screen-form .title {
  --left: 1;
  --width: 12;
}

.full-screen-form .field {
  display: grid;
  gap: var(--m);
}

.full-screen-form input,
.full-screen-form textarea {
  background-color: rgba(var(--c-white-rgb), 0.05);
  border: 1px solid var(--c-grey);
  border-radius: var(--g-gap);
  padding: var(--m) var(--p);
  color: var(--c-white);
  width: 100%;
}

.full-screen-form input:focus,
.full-screen-form textarea:focus {
  border-color: var(--c-yellow);
  outline: none;
}

.full-screen-form .agreement label {
  display: flex;
  gap: var(--m);
  align-items: flex-start;
  color: rgba(var(--c-white-rgb), 0.6);
}

.full-screen-form .button-wrap {
  display: flex;
  justify-content: flex-start;
}

/* Generic button */
.button.-big {
  background-color: var(--c-yellow);
  color: var(--c-black);
  font-family: var(--font-b-medium);
  font-weight: 600;
  font-size: var(--m);
  text-transform: uppercase;
  letter-spacing: 0.08em;
  padding: var(--m) var(--h3);
  border-radius: 100px;
  cursor: pointer;
  transition: background-color 0.3s var(--f-cubic), color 0.3s var(--f-cubic);
}

.button.-big:hover {
  background-color: var(--c-white);
}

/* Success modal */
.submission-modal {
  position: fixed;
  inset: 0;
  z-index: 300;
  display: flex;
  align-items: center;
  justify-content: center;
}

.submission-modal .overlay {
  position: absolute;
  inset: 0;
  background-color: rgba(var(--c-black-rgb), 0.8);
