/* ===== PAGE TRANSITION OVERLAY ===== */

#page-transition {
  position: fixed;
  inset: 0;
  z-index: 9999;
  pointer-events: none;
}

#page-transition .g {
  display: grid;
  grid-template-columns: repeat(4, 1fr);
  height: 100%;
}

#page-transition .g span {
  background-color: var(--c-black);
  transform: scaleY(0);
  transform-origin: bottom center;
}

#page-transition.-active .g span {
  transform: scaleY(1);
  transition: transform 0.6s var(--f-fast);
  transition-delay: calc((var(--order) - 1) * 0.07s);
}

#page-transition .t {
  position: absolute;
  inset: 0;
  display: flex;
  align-items: center;
  justify-content: center;
  opacity: 0;
  transition: opacity 0.3s var(--f-cubic);
}

#page-transition.-active .t {
  opacity: 1;
  transition-delay: 0.5s;
}

#page-transition .t span {
  color: var(--c-yellow);
  display: flex;
  flex-direction: column;
  align-items: flex-start;
}

#mobile-transition {
  position: fixed;
  inset: 0;
  z-index: 9998;
  background-color: var(--c-black);
  transform: scaleY(0);
  transform-origin: bottom center;
  pointer-events: none;
}

#mobile-transition.-active {
  transform: scaleY(1);
  transition: transform 0.5s var(--f-fast);
}

/* Overlay / full-screen menu & form base */
.full-screen-menu,
.full-screen-form {
  position: fixed;
  inset: 0;
  z-index: 200;
  overflow: hidden;
}

.full-screen-menu .overlay,
.full-screen-form .overlay {
  position: absolute;
  inset: 0;
  background-color: rgba(var(--c-black-rgb), 0.6);
  backdrop-filter: blur(4px);
}

.full-screen-menu .oy,
.full-screen-form .oy {
  position: absolute;
  inset: 0;
  overflow-y: auto;
  padding: var(--h1) 0 var(--h2);
}

.full-screen-menu .-w,
.full-screen-form .-w {
  position: relative;
  z-index: 1;
}

.button-close {
  --left: 11;
