#mobile-transition {
  position: fixed;
  inset: 0;
  z-index: 9998;
  background-color: var(--c-black);
  transform: scaleY(0);
  transform-origin: bottom center;
  pointer-events: none;
}

#mobile-transition.-active {
  transform: scaleY(1);
  transition: transform 0.5s var(--f-fast);
}

/* Overlay / full-screen menu & form base */
.full-screen-menu,
.full-screen-form {
  position: fixed;
  inset: 0;
  z-index: 200;
  overflow: hidden;
}

.full-screen-menu .overlay,
.full-screen-form .overlay {
  position: absolute;
  inset: 0;
  background-color: rgba(var(--c-black-rgb), 0.6);
  backdrop-filter: blur(4px);
}

.full-screen-menu .oy,
.full-screen-form .oy {
  position: absolute;
  inset: 0;
  overflow-y: auto;
  padding: var(--h1) 0 var(--h2);
}

.full-screen-menu .-w,
.full-screen-form .-w {
  position: relative;
  z-index: 1;
}

.button-close {
  --left: 11;
  --width: 2;
  color: var(--c-yellow);
  font-family: var(--font-b-medium);
  font-size: var(--mm);
  text-transform: uppercase;
  letter-spacing: 0.1em;
  cursor: pointer;
  align-self: start;
}

/* Menu nav */
.full-screen-menu nav {
  --left: 1;
  --width: 12;
  display: flex;
  flex-direction: column;
  gap: var(--g-gap);
  padding-top: var(--h1);
}

.full-screen-menu nav .guy {
  display: flex;
  align-items: center;
  gap: var(--p);
  margin-bottom: var(--h3);
}

.full-screen-menu nav .guy img {
  width: 60px;
  height: 60px;
  border-radius: 50%;
  object-fit: cover;
  flex-shrink: 0;
}

.full-screen-menu nav a,
.full-screen-menu nav span {
  color: var(--c-yellow);
  display: block;
  font-family: var(--font-t-1);
}

